// Limita a los N más recientes actualizados para acotar coste.
// Cambia este número si quieres más profundidad.
const MAX = 250;
const tickets = $input.all().map(i => i.json).filter(t => t && t.id);
tickets.sort((a,b) => new Date(b.updated_at) - new Date(a.updated_at));
const limited = tickets.slice(0, MAX);
return limited.map(t => ({ json: t }));

// Para cada ticket open, compara requester_updated_at vs assignee_updated_at
// del ticket_metric. Esto refleja exactamente el campo 'Último en actualizar'
// de Zendesk: requester gana → user fue el último; assignee gana → agente.
const tickets = $('Limitar a 250').all().map(i => i.json);
const metricResps = $input.all().map(i => i.json);

const matches = [];
let skipped = 0;
let lastByAgent = 0;
let lastByUser  = 0;

for (let i = 0; i < tickets.length; i++) {
  const t = tickets[i];
  const m = (metricResps[i] && metricResps[i].ticket_metric) || null;
  if (!m) { skipped++; continue; }

  const ru = m.requester_updated_at ? new Date(m.requester_updated_at).getTime() : 0;
  const au = m.assignee_updated_at  ? new Date(m.assignee_updated_at).getTime()  : 0;
  const ageDays = t.created_at ? Math.floor((Date.now() - new Date(t.created_at).getTime()) / 86400000) : null;

  const userIsLast = ru > au;
  if (userIsLast) lastByUser++;
  else lastByAgent++;

  if (userIsLast) {
    const sinceDays = m.requester_updated_at ? Math.floor((Date.now() - ru) / 86400000) : null;
    matches.push({
      ticket_id: t.id,
      subject: t.subject,
      status: t.status,
      age_days: ageDays,
      days_since_user_updated: sinceDays,
      requester_updated_at: m.requester_updated_at,
      assignee_updated_at:  m.assignee_updated_at,
      latest_comment_added_at: m.latest_comment_added_at,
      requester_id: t.requester_id,
      assignee_id: t.assignee_id,
      url: `https://soporteyurest.zendesk.com/agent/tickets/${t.id}`
    });
  }
}

matches.sort((a,b) => (a.days_since_user_updated ?? 999) - (b.days_since_user_updated ?? 999));

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_open_total: tickets.length,
  tickets_skipped_no_metric: skipped,
  last_by_user_count:  lastByUser,
  last_by_agent_count: lastByAgent,
  needs_agent_reply_count: matches.length,
  needs_agent_reply_ids_csv: matches.map(m => m.ticket_id).join(','),
  needs_agent_reply: matches
} }];
